// Parse Slack event body and handle URL verification challenge
const body = $input.first().json.body;
const headers = $input.first().json.headers;

// URL verification handshake (Slack sends this on initial setup)
if (body.type === 'url_verification') {
  return [{ json: { _type: 'challenge', challenge: body.challenge } }];
}

// Only process message events in channels
const event = body.event;
if (!event) return [{ json: { _type: 'ignored' } }];
if (event.type !== 'app_mention') return [{ json: { _type: 'ignored' } }]; // only handle @mentions, not duplicate message events
if (event.bot_id || event.subtype) return [{ json: { _type: 'ignored' } }]; // ignore bot messages

return [{
  json: {
    _type: 'message',
    text: event.text || '',
    user_id: event.user,
    channel: event.channel,
    ts: event.ts,
    team_id: body.team_id
  }
}];

// Parse Claude response and fuzzy-match against catalog
const claudeRaw = $input.first().json.content[0].text;
let extracted;
try {
  let raw = claudeRaw.trim();
  if (raw.startsWith('```')) {
    raw = raw.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
  }
  extracted = JSON.parse(raw);
} catch(e) { return [{ json: { _type: 'no_match', reason: 'claude_parse_error', raw: claudeRaw } }]; }

if (extracted.intent !== 'access_request' || !extracted.app) {
  return [{ json: { _type: 'no_match', reason: 'not_access_request', extracted } }];
}

// Hardcoded catalog (synced from catalog/entitlements.json)
const catalog = [
  {
    app_id: '2CAfu61AAA3heEItnkkKHsLdSak',
    entitlement_id: '3B8ghDszuxqUa0DnZcCvakCv5Em',
    app_name: 'Okta Teams & Groups',
    label: 'Team-IT-Pilot',
    description: 'Member of the Team-IT-Pilot Okta group.',
    risk: 'low',
    aliases: ['team-it-pilot', 'team it pilot', 'it pilot', 'pilot'],
    approver_note: 'Routes to the IT team owner for approval.'
  }
];

// Fuzzy scoring
const appInput = (extracted.app || '').toLowerCase().trim();
let bestMatch = null, bestScore = 0;

for (const entry of catalog) {
  let score = 0;
  const label = entry.label.toLowerCase();
  const name = entry.app_name.toLowerCase();

  if (appInput === label || appInput === name) score += 10;
  else if (label.includes(appInput) || appInput.includes(label)) score += 5;
  else if (name.includes(appInput) || appInput.includes(name)) score += 4;

  for (const alias of entry.aliases) {
    if (appInput === alias) { score += 10; break; }
    if (alias.includes(appInput) || appInput.includes(alias)) { score += 5; break; }
  }

  if (extracted.role) {
    const role = extracted.role.toLowerCase();
    if (entry.label.toLowerCase().includes(role)) score += 3;
  }

  if (score > bestScore) { bestScore = score; bestMatch = entry; }
}

if (!bestMatch || bestScore < 4) {
  return [{ json: { _type: 'no_match', reason: 'no_catalog_match', extracted } }];
}

// Pull Slack context from earlier node
const slackCtx = $('Parse Slack Event').first().json;

return [{
  json: {
    _type: 'match',
    extracted,
    match: bestMatch,
    score: bestScore,
    slack_user_id: slackCtx.user_id,
    slack_channel: slackCtx.channel,
    slack_ts: slackCtx.ts
  }
}];

