// Slack interactions come as URL-encoded form with a 'payload' field
const body = $input.first().json.body;
let payload;
try {
  const raw = typeof body === 'string' ? body : body.payload;
  payload = JSON.parse(decodeURIComponent(raw));
} catch(e) {
  // body already parsed by n8n
  payload = body.payload ? JSON.parse(body.payload) : body;
}

const action = payload.actions && payload.actions[0];
if (!action) return [{ json: { _type: 'no_action' } }];

if (action.action_id === 'cancel_request') {
  return [{ json: { _type: 'cancelled', user_id: payload.user.id, channel: payload.channel.id, response_url: payload.response_url } }];
}

if (action.action_id === 'confirm_request') {
  const parts = (action.value || '').split('|');
  const value = { app_id: parts[0], entitlement_id: parts[1], label: parts[2], app_name: parts[3], justification: parts[4] || '' };
  return [{
    json: {
      _type: 'confirmed',
      app_id: value.app_id,
      entitlement_id: value.entitlement_id,
      label: value.label,
      app_name: value.app_name,
      justification: value.justification,
      slack_user_id: payload.user.id,
      slack_user_email: payload.user.email || null,
      slack_team_id: payload.team.id,
      channel: payload.channel ? payload.channel.id : null,
      response_url: payload.response_url
    }
  }];
}

return [{ json: { _type: 'unknown_action', action_id: action.action_id } }];

// Merge Slack user email + C1 token for next steps
const slackUser = $('Get Slack User Email').first().json;
const c1Token = $('Get C1 Token').first().json;
const interaction = $('Parse Interaction').first().json;

const email = slackUser.user && slackUser.user.profile && slackUser.user.profile.email;
if (!email) throw new Error('Could not retrieve Slack user email. Ensure users:read.email scope is granted.');

return [{
  json: {
    email,
    c1_token: c1Token.access_token,
    app_id: interaction.app_id,
    entitlement_id: interaction.entitlement_id,
    label: interaction.label,
    app_name: interaction.app_name,
    justification: interaction.justification,
    slack_user_id: interaction.slack_user_id,
    channel: interaction.channel,
    response_url: interaction.response_url
  }
}];

const ctx = $('Merge Email + Token').first().json;
const targetEmail = (ctx.email || '').toLowerCase();

const users = $input.first().json.list || [];
const match = users.find(u => (u.user?.email || u.email || '').toLowerCase() === targetEmail);
if (!match) throw new Error('C1 user not found for email: ' + targetEmail);

const c1UserId = match.user?.id || match.id;
if (!c1UserId) throw new Error('C1 user record missing id field');

return [{
  json: {
    c1_token: ctx.c1_token,
    c1_user_id: c1UserId,
    app_id: ctx.app_id,
    entitlement_id: ctx.entitlement_id,
    label: ctx.label,
    app_name: ctx.app_name,
    justification: ctx.justification,
    slack_user_id: ctx.slack_user_id,
    channel: ctx.channel,
    response_url: ctx.response_url,
    email: ctx.email
  }
}];

